insert into sd_navi_comment values (1000001, 1000, '様々なミニゲームをご用意してい\\nますよ！\\nどのミニゲームで遊びますか？', 190801, 13, 0, '2030-04-01 14:00:00', '2020-02-15 15:00:00');
insert into sd_navi_comment values (1000002, 1000, '楽しいミニゲームをご紹介！\\nあなたはどのミニゲームで\\n遊びますか？', 190801, 13, 0, '2030-04-01 14:00:00', '2020-02-15 15:00:00');
insert into sd_navi_comment values (1001001, 1001, 'こちらは{0}ルピで\\n販売中！\\nぜひ購入して\\n遊んでくださいね！', 190801, 13, 0, '2030-04-01 14:00:00', '2020-02-15 15:00:00');
insert into sd_navi_comment values (1002001, 1002, '動くハートに合わせてタップ！\\nシズルさんとエリコさんの\\nチョコレートケーキ作りを\\nお手伝いしましょう！', 190801, 12, 0, '2030-04-01 14:00:00', '2020-02-15 15:00:00');
insert into sd_navi_comment values (1003001, 1003, 'クウカさんを引っ張ってより遠く\\nへ飛ばしてあげましょう！\\n色々なハプニングでクウカさんに\\nエクスタシーを届けましょう！', 190801, 11, 0, '2030-04-01 14:00:00', '2020-02-15 15:00:00');
insert into sd_navi_comment values (1004001, 1004, '左右をタップしてマジムンを倒し\\nましょう！\\n放て！\\n琉球犬アラウンドシュート！', 190801, 3, 0, '2030-04-01 14:00:00', '2020-02-15 15:00:00');
insert into sd_navi_comment values (1005001, 1005, 'パネルをタップしてドラゴンズ\\nネストのみなさんと一緒に\\nしりとり対決をしませんか？\\nおしりに「ん」はご法度です。', 190801, 7, 0, '2030-04-01 14:00:00', '2020-02-15 15:00:00');
insert into sd_navi_comment values (1006001, 1006, '素早い動きのネズミに合わせ、\\nタップで撃退！\\nやる気のリンさんと一緒に\\n大切なチーズを守りましょう！', 190801, 2, 0, '2030-04-01 14:00:00', '2020-05-31 12:00:00');
insert into sd_navi_comment values (1007001, 1007, 'ミサトさんや部員のみなさんと\\nバッティングの特訓ですよ！\\nホームランを目指して、ボールを\\nタイミングよく打ち返しましょう', 190801, 4, 0, '2030-04-01 14:00:00', '2020-08-15 15:00:00');
insert into sd_navi_comment values (1008001, 1008, 'カルミナメダルを使って、\\n応援グッズをゲットしましょう！\\nメダルはルピを使って\\n交換できますよ。\\n', 190801, 6, 0, '2030-04-01 14:00:00', '2021-08-31 12:00:00');
insert into sd_navi_comment values (1009001, 1009, '食べたプリンはプリンノート\\nで確認してみましょう！\\nプリンの材料はルピを使って\\n購入できますよ。', 190801, 13, 0, '2030-04-01 14:00:00', '2021-12-18 15:00:00');
insert into sd_navi_comment values (1010001, 1010, 'チームでクイズに挑みましょう！\\nソロで自分の実力を試すか、マル\\nチで仲間と一緒に遊ぶか、好きな\\nモードを選んでくださいね♪', 190801, 4, 0, '2030-04-01 14:00:00', '2022-02-15 15:00:00');
insert into sd_navi_comment values (1011001, 1011, '３つのラウンドを駆け抜け、\\n総合１位を目指しましょう！\\n参加者の皆さんの特徴や、\\nＧＰの特徴にも注目です♪', 190801, 6, 0, '2030-04-01 14:00:00', '2022-07-18 15:00:00');
insert into sd_navi_comment values (1012001, 1012, 'キャルさん、スズナさんと一緒に\\nクイズでお勉強しましょう！\\n放課後の教室で二人きりって…\\nなんだかドキドキしますね♪', 190801, 6, 0, '2030-04-01 14:00:00', '2023-09-18 15:00:00');
insert into sd_navi_comment values (1013001, 1013, '魔物の討伐任務にいざ行軍！\\nエリコさん、マコトさんの\\n頼もしい背中は、\\n新兵さんたちの憧れですね♪', 190801, 6, 0, '2030-04-01 14:00:00', '2024-04-18 15:00:00');
